class LRUCache {
    Map<Integer, Node> cache = new HashMap<>();
    Node head, tail;
    int cap;

    void moveToHead(Node node) { // 删除并加到头
        remove(node);
        addHead(node);
    }

    int get(int key) {
        Node node = cache.get(key);
        if(node == null) return -1;
        moveToHead(node);
        return node.val;
    }

    void put(int key, int val) {
        Node node = cache.get(key);
        if(node != null) {
            node.val = val;
            moveToHead(node);
        } else {
            Node newNode = new Node(key, val);
            addHead(newNode);
            cache.put(key, newNode);
            if(cache.size() > cap) {
                Node tail = removeTail();
                cache.remove(tail.key);
            }
        }
    }
}
```

