def letterCombinations(digits):
    mapping = {'2':'abc','3':'def','4':'ghi',...}
    result = []

    def backtrack(index, path):
        if index == len(digits):
            result.append(''.join(path))
            return
        for letter in mapping[digits[index]]:
            path.append(letter)
            backtrack(index+1, path)
            path.pop()

    if digits: backtrack(0, [])
    return result
