        if row == n:
            res.append(path)
            return
        for col in range(n):
            c = 1 << col
            d = 1 << (row + col)  # 主对角线
            e = 1 << (row - col + n-1)  # 副对角线
            if not (c & cols or d & diff or e & (diff >> 1)):
                dfs(row+1, cols|c, (diff|d)<<1, path+[col])
    res = []
    dfs(0, 0, 0, [])
    return res

