class MinStack:
    def __init__(self):
        self.stack = []
        self.minStack = []

    def push(self, x):
        self.stack.append(x)
        if not self.minStack or x <= self.minStack[-1]:
            self.minStack.append(x)

    def pop(self):
        if self.stack.pop() == self.minStack[-1]:
            self.minStack.pop()

    def top(self): return self.stack[-1]
    def getMin(self): return self.minStack[-1]
```

