def quickSelect(nums, k):
    pivot = partition(nums)  # 划分
    if pivot == k-1: return nums[pivot]
    if pivot > k-1: return quickSelect(nums[:pivot], k)
    return quickSelect(nums[pivot+1:], k-pivot-1)
